// EmployeeManagementServiceImpl.java (SIB - Service Implementation Bean)
package com.hr.service;

import com.hr.data.EmployeeDataStore;
import com.hr.exception.EmployeeManagementException;
import com.hr.exception.EmployeeManagementFault;
import com.hr.model.*;

import javax.jws.WebService;
import java.time.LocalDate;
import java.time.format.DateTimeFormatter;
import java.time.format.DateTimeParseException;
import java.util.ArrayList;
import java.util.List;
import java.util.logging.Level;
import java.util.logging.Logger;

@WebService(
    endpointInterface = "com.hr.service.EmployeeManagementService",
    serviceName = "EmployeeManagementWebService",
    portName = "EmployeeManagementPort",
    targetNamespace = "http://hr.com/employee/service",
    wsdlLocation = "EmployeeManagementService.wsdl"
)
public class EmployeeManagementServiceImpl implements EmployeeManagementService {

    private static final Logger LOGGER = Logger.getLogger(EmployeeManagementServiceImpl.class.getName());
    private final EmployeeDataStore dataStore = EmployeeDataStore.getInstance();
    private static final DateTimeFormatter DATE_FORMATTER = DateTimeFormatter.ISO_LOCAL_DATE;

    // === Employee Lookup Operations ===

    @Override
    public Employee getEmployee(int employeeId) throws EmployeeManagementFault {
        LOGGER.info("Getting employee with ID: " + employeeId);
        Employee employee = dataStore.getEmployee(employeeId);
        if (employee == null) {
            throw createFault("Employee not found with ID: " + employeeId, "EMP_NOT_FOUND");
        }
        return employee;
    }

    @Override
    public List<Employee> getAllActiveEmployees() throws EmployeeManagementFault {
        LOGGER.info("Retrieving all active employees");
        try {
            List<Employee> activeEmployees = dataStore.getActiveEmployees();
            LOGGER.info("Found " + activeEmployees.size() + " active employees");
            return activeEmployees;
        } catch (Exception e) {
            throw createFault("Error retrieving active employees: " + e.getMessage(), "RETRIEVAL_ERROR");
        }
    }

    @Override
    public List<Employee> getEmployeesByDepartment(String department) throws EmployeeManagementFault {
        if (department == null || department.trim().isEmpty()) {
            throw createFault("Department name cannot be empty", "INVALID_DEPARTMENT");
        }
        LOGGER.info("Retrieving employees for department: " + department);
        return dataStore.getEmployeesByDepartment(department);
    }

    // === Salary Operations ===

    @Override
    public SalaryUpdateResult updateSalary(int employeeId, double newSalary,
                                            String effectiveDate, String reason) throws EmployeeManagementFault {
        LOGGER.info("Updating salary for employee " + employeeId + " to " + newSalary);

        validateSalary(newSalary);
        validateDate(effectiveDate);

        Employee employee = getValidatedEmployee(employeeId);
        validateEmployeeActive(employee);

        double previousSalary = employee.getSalary();

        if (newSalary == previousSalary) {
            return new SalaryUpdateResult(false, "New salary is the same as current salary",
                    employeeId, previousSalary, newSalary, effectiveDate);
        }

        employee.setSalary(newSalary);
        dataStore.updateEmployee(employee);

        String message = String.format("Salary updated from %.2f to %.2f. Reason: %s",
                previousSalary, newSalary, reason != null ? reason : "Not specified");

        LOGGER.info(message);
        return new SalaryUpdateResult(true, message, employeeId, previousSalary, newSalary, effectiveDate);
    }

    @Override
    public SalaryUpdateResult applyPercentageRaise(int employeeId, double percentageIncrease,
                                                    String effectiveDate) throws EmployeeManagementFault {
        LOGGER.info("Applying " + percentageIncrease + "% raise for employee " + employeeId);

        if (percentageIncrease <= 0 || percentageIncrease > 100) {
            throw createFault("Percentage increase must be between 0 and 100", "INVALID_PERCENTAGE");
        }

        validateDate(effectiveDate);

        Employee employee = getValidatedEmployee(employeeId);
        validateEmployeeActive(employee);

        double previousSalary = employee.getSalary();
        double raiseAmount = previousSalary * (percentageIncrease / 100.0);
        double newSalary = Math.round((previousSalary + raiseAmount) * 100.0) / 100.0;

        employee.setSalary(newSalary);
        dataStore.updateEmployee(employee);

        String message = String.format("Applied %.2f%% raise. Salary updated from %.2f to %.2f (increase: %.2f)",
                percentageIncrease, previousSalary, newSalary, raiseAmount);

        LOGGER.info(message);
        return new SalaryUpdateResult(true, message, employeeId, previousSalary, newSalary, effectiveDate);
    }

    @Override
    public List<SalaryUpdateResult> applyDepartmentWideRaise(String department, double percentageIncrease,
                                                              String effectiveDate) throws EmployeeManagementFault {
        LOGGER.info("Applying " + percentageIncrease + "% department-wide raise for " + department);

        if (department == null || department.trim().isEmpty()) {
            throw createFault("Department name cannot be empty", "INVALID_DEPARTMENT");
        }

        if (percentageIncrease <= 0 || percentageIncrease > 50) {
            throw createFault("Department-wide percentage increase must be between 0 and 50", "INVALID_PERCENTAGE");
        }

        validateDate(effectiveDate);

        List<Employee> deptEmployees = dataStore.getEmployeesByDepartment(department);
        if (deptEmployees.isEmpty()) {
            throw createFault("No employees found in department: " + department, "DEPT_EMPTY");
        }

        List<SalaryUpdateResult> results = new ArrayList<>();
        for (Employee employee : deptEmployees) {
            if ("ACTIVE".equals(employee.getStatus())) {
                try {
                    SalaryUpdateResult result = applyPercentageRaise(employee.getEmployeeId(),
                            percentageIncrease, effectiveDate);
                    results.add(result);
                } catch (EmployeeManagementFault e) {
                    results.add(new SalaryUpdateResult(false,
                            "Failed: " + e.getMessage(),
                            employee.getEmployeeId(), employee.getSalary(), employee.getSalary(), effectiveDate));
                }
            }
        }

        LOGGER.info("Department-wide raise applied to " + results.size() + " employees in " + department);
        return results;
    }

    // === Performance Review Operations ===

    @Override
    public ReviewResult submitPerformanceReview(PerformanceReview review) throws EmployeeManagementFault {
        LOGGER.info("Submitting performance review for employee " + review.getEmployeeId());

        if (review == null) {
            throw createFault("Performance review cannot be null", "INVALID_REVIEW");
        }

        Employee employee = getValidatedEmployee(review.getEmployeeId());
        validateEmployeeActive(employee);

        // Validate scores
        validateScore(review.getProductivityScore(), "Productivity");
        validateScore(review.getTeamworkScore(), "Teamwork");
        validateScore(review.getLeadershipScore(), "Leadership");
        validateScore(review.getCommunicationScore(), "Communication");

        // Calculate overall score if not provided
        double overallScore = review.getOverallScore();
        if (overallScore <= 0) {
            overallScore = (review.getProductivityScore() + review.getTeamworkScore() +
                    review.getLeadershipScore() + review.getCommunicationScore()) / 4.0;
            overallScore = Math.round(overallScore * 100.0) / 100.0;
            review.setOverallScore(overallScore);
        } else {
            validateScore(overallScore, "Overall");
        }

        if (review.getReviewDate() == null || review.getReviewDate().isEmpty()) {
            review.setReviewDate(LocalDate.now().format(DATE_FORMATTER));
        }

        // Determine promotion recommendation based on score
        boolean promotionRecommended = review.isPromotionRecommended() || overallScore >= 4.5;
        review.setPromotionRecommended(promotionRecommended);

        // Calculate suggested salary increase
        double suggestedIncrease = calculateSuggestedRaise(overallScore);

        // Store the review
        dataStore.addReview(review.getEmployeeId(), review);

        // Update employee's performance score
        employee.setPerformanceScore(overallScore);
        dataStore.updateEmployee(employee);

        String message = String.format("Performance review submitted. Overall score: %.2f. %s",
                overallScore,
                promotionRecommended ? "Promotion recommended." : "No promotion recommended at this time.");

        LOGGER.info(message);
        return new ReviewResult(true, message, review.getReviewId(), review.getEmployeeId(),
                overallScore, promotionRecommended, suggestedIncrease);
    }

    @Override
    public List<PerformanceReview> getPerformanceReviews(int employeeId) throws EmployeeManagementFault {
        LOGGER.info("Retrieving performance reviews for employee " + employeeId);
        getValidatedEmployee(employeeId); // Validate employee exists
        return dataStore.getReviews(employeeId);
    }

    @Override
    public double getLatestPerformanceScore(int employeeId) throws EmployeeManagementFault {
        Employee employee = getValidatedEmployee(employeeId);
        return employee.getPerformanceScore();
    }

    // === Termination Operations ===

    @Override
    public TerminationResult terminateEmployee(int employeeId, String terminationDate,
                                                String reason, boolean eligibleForRehire) throws EmployeeManagementFault {
        LOGGER.info("Processing termination for employee " + employeeId);

        validateDate(terminationDate);

        if (reason == null || reason.trim().isEmpty()) {
            throw createFault("Termination reason is required", "INVALID_REASON");
        }

        Employee employee = getValidatedEmployee(employeeId);

        if ("TERMINATED".equals(employee.getStatus())) {
            throw createFault("Employee " + employeeId + " is already terminated", "ALREADY_TERMINATED");
        }

        // Calculate final pay (simplified: remaining salary for the month + any accrued benefits)
        double finalPayAmount = calculateFinalPay(employee);

        // Update employee status
        employee.setStatus("TERMINATED");
        employee.setTerminationDate(terminationDate);
        dataStore.updateEmployee(employee);

        String message = String.format("Employee %s %s (ID: %d) terminated on %s. Reason: %s. Final pay: %.2f. %s",
                employee.getFirstName(), employee.getLastName(), employeeId,
                terminationDate, reason, finalPayAmount,
                eligibleForRehire ? "Eligible for rehire." : "Not eligible for rehire.");

        LOGGER.info(message);
        return new TerminationResult(true, message, employeeId, terminationDate,
                reason, finalPayAmount, eligibleForRehire);
    }

    @Override
    public boolean rehireEmployee(int employeeId, String newPosition,
                                   double newSalary, String rehireDate) throws EmployeeManagementFault {
        LOGGER.info("Processing rehire for employee " + employeeId);

        validateDate(rehireDate);
        validateSalary(newSalary);

        if (newPosition == null || newPosition.trim().isEmpty()) {
            throw createFault("New position is required for rehire", "INVALID_POSITION");
        }

        Employee employee = dataStore.getEmployee(employeeId);
        if (employee == null) {
            throw createFault("Employee not found with ID: " + employeeId, "EMP_NOT_FOUND");
        }

        if (!"TERMINATED".equals(employee.getStatus())) {
            throw createFault("Employee " + employeeId + " is not terminated. Current status: " + employee.getStatus(),
                    "NOT_TERMINATED");
        }

        // Rehire the employee
        employee.setStatus("ACTIVE");
        employee.setPosition(newPosition);
        employee.setSalary(newSalary);
        employee.setHireDate(rehireDate);
        employee.setTerminationDate(null);
        employee.setPerformanceScore(3.0); // Reset performance score
        dataStore.updateEmployee(employee);

        LOGGER.info("Employee " + employeeId + " rehired successfully as " + newPosition);
        return true;
    }

    // === Helper Methods ===

    private Employee getValidatedEmployee(int employeeId) throws EmployeeManagementFault {
        Employee employee = dataStore.getEmployee(employeeId);
        if (employee == null) {
            throw createFault("Employee not found with ID: " + employeeId, "EMP_NOT_FOUND");
        }
        return employee;
    }

    private void validateEmployeeActive(Employee employee) throws EmployeeManagementFault {
        if (!"ACTIVE".equals(employee.getStatus())) {
            throw createFault("Employee " + employee.getEmployeeId() + " is not active. Current status: " +
                    employee.getStatus(), "EMP_NOT_ACTIVE");
        }
    }

    private void validateSalary(double salary) throws EmployeeManagementFault {
        if (salary <= 0) {
            throw createFault("Salary must be a positive value", "INVALID_SALARY");
        }
        if (salary > 10000000) {
            throw createFault("Salary exceeds maximum allowed value", "SALARY_EXCEEDS_MAX");
        }
    }

    private void validateDate(String date) throws EmployeeManagementFault {
        if (date == null || date.trim().isEmpty()) {
            throw createFault("Date cannot be empty", "INVALID_DATE");
        }
        try {
            LocalDate.parse(date, DATE_FORMATTER);
        } catch (DateTimeParseException e) {
            throw createFault("Invalid date format. Expected format: yyyy-MM-dd. Got: " + date, "INVALID_DATE_FORMAT");
        }
    }

    private void validateScore(double score, String scoreName) throws EmployeeManagementFault {
        if (score < 1.0 || score > 5.0) {
            throw createFault(scoreName + " score must be between 1.0 and 5.0. Got: " + score, "INVALID_SCORE");
        }
    }

    private double calculateSuggestedRaise(double overallScore) {
        if (overallScore >= 4.5) return 15.0;
        if (overallScore >= 4.0) return 10.0;
        if (overallScore >= 3.5) return 7.0;
        if (overallScore >= 3.0) return 5.0;
        if (overallScore >= 2.5) return 2.0;
        return 0.0;
    }

    private double calculateFinalPay(Employee employee) {
        // Simplified calculation: prorated monthly salary + severance equivalent
        double monthlySalary = employee.getSalary() / 12.0;
        double severance = monthlySalary * 2; // 2 months severance
        return Math.round((monthlySalary + severance) * 100.0) / 100.0;
    }

    private EmployeeManagementFault createFault(String message, String errorCode) {
        LOGGER.log(Level.WARNING, "Fault: [{0}] {1}", new Object[]{errorCode, message});
        EmployeeManagementException exception = new EmployeeManagementException(message, errorCode);
        return new EmployeeManagementFault(message, exception);
    }
}

// EmployeeManagementPublisher.java
package com.hr;

import com.hr.service.EmployeeManagementServiceImpl;

import javax.xml.ws.Endpoint;
import java.util.logging.Logger;

public class EmployeeManagementPublisher {

    private static final Logger LOGGER = Logger.getLogger(EmployeeManagementPublisher.class.getName());
    private static final String SERVICE_URL = "http://localhost:8080/hr/employee-management";
    private static Endpoint endpoint;

    public static void main(String[] args) {
        publishService();

        // Add shutdown hook for graceful shutdown
        Runtime.getRuntime().addShutdownHook(new Thread(() -> {
            LOGGER.info("Shutting down Employee Management Service...");
            stopService();
        }));

        LOGGER.info("Press Ctrl+C to stop the service.");
    }

    public static void publishService() {
        try {
            EmployeeManagementServiceImpl serviceImpl = new EmployeeManagementServiceImpl();
            endpoint = Endpoint.publish(SERVICE_URL, serviceImpl);

            LOGGER.info("====================================================");
            LOGGER.info("HR Employee Management SOAP Web Service Published");
            LOGGER.info("Service URL: " + SERVICE_URL);
            LOGGER.info("WSDL URL:    " + SERVICE_URL + "?wsdl");
            LOGGER.info("====================================================");
            LOGGER.info("Available Operations:");
            LOGGER.info("  - getEmployee(employeeId)");
            LOGGER.info("  - getAllActiveEmployees()");
            LOGGER.info("  - getEmployeesByDepartment(department)");
            LOGGER.info("  - updateSalary(employeeId, newSalary, effectiveDate, reason)");
            LOGGER.info("  - applyPercentageRaise(employeeId, percentageIncrease, effectiveDate)");
            LOGGER.info("  - applyDepartmentWideRaise(department, percentageIncrease, effectiveDate)");
            LOGGER.info("  - submitPerformanceReview(review)");
            LOGGER.info("  - getPerformanceReviews(employeeId)");
            LOGGER.info("  - getLatestPerformanceScore(employeeId)");
            LOGGER.info("  - terminateEmployee(employeeId, terminationDate, reason, eligibleForRehire)");
            LOGGER.info("  - rehireEmployee(employeeId, newPosition, newSalary, rehireDate)");
            LOGGER.info("====================================================");

        } catch (Exception e) {
            LOGGER.severe("Failed to publish Employee Management Service: " + e.getMessage());
            e.printStackTrace();
        }
    }

    public static void stopService() {
        if (endpoint != null && endpoint.isPublished()) {
            endpoint.stop();
            LOGGER.info("Employee Management Service stopped.");
        }
    }

    public static boolean isPublished() {
        return endpoint != null && endpoint.isPublished();
    }
}

// EmployeeManagementClient.java (Test client)
package com.hr.client;

import com.hr.exception.EmployeeManagementFault;
import com.hr.model.*;
import com.hr.service.EmployeeManagementService;

import javax.xml.namespace.QName;
import javax.xml.ws.Service;
import java.net.URL;
import java.time.LocalDate;
import java.util.List;
import java.util.logging.Logger;

public class EmployeeManagementClient {

    private static final Logger LOGGER = Logger.getLogger(EmployeeManagementClient.class.getName());
    private static final String WSDL_URL = "http://localhost:8080/hr/employee-management?wsdl";
    private static final String NAMESPACE = "http://hr.com/employee/service";
    private static final String SERVICE_NAME = "EmployeeManagementWebService";

    public static void main(String[] args) {
        try {
            // Create service connection
            URL wsdlUrl = new URL(WSDL_URL);
            QName qname = new QName(NAMESPACE, SERVICE_NAME);
            Service service = Service.create(wsdlUrl, qname);
            EmployeeManagementService employeeService = service.getPort(EmployeeManagementService.class);

            LOGGER.info("Connected to Employee Management Service");
            LOGGER.info("==========================================");

            // Test 1: Get Employee
            testGetEmployee(employeeService);

            // Test 2: Get All Active Employees
            testGetAllActiveEmployees(employeeService);

            // Test 3: Get Employees By Department
            testGetEmployeesByDepartment(employeeService);

            // Test 4: Update Salary
            testUpdateSalary(employeeService);

            // Test 5: Apply Percentage Raise
            testApplyPercentageRaise(employeeService);

            // Test 6: Department Wide Raise
            testDepartmentWideRaise(employeeService);

            // Test 7: Submit Performance Review
            testSubmitPerformanceReview(employeeService);

            // Test 8: Get Performance Reviews
            testGetPerformanceReviews(employeeService);

            // Test 9: Terminate Employee
            testTerminateEmployee(employeeService);

            // Test 10: Rehire Employee
            testRehireEmployee(employeeService);

            // Test 11: Error handling
            testErrorHandling(employeeService);

        } catch (Exception e) {
            LOGGER.severe("Client error: " + e.getMessage());
            e.printStackTrace();
        }
    }

    private static void testGetEmployee(EmployeeManagementService service) throws EmployeeManagementFault {
        LOGGER.info("\n--- Test: Get Employee ---");
        Employee emp = service.getEmployee(1001);
        LOGGER.info("Employee: " + emp.getFirstName() + " " + emp.getLastName() +
                " | Dept: " + emp.getDepartment() + " | Salary: $" + emp.getSalary());
    }

    private static void testGetAllActiveEmployees(EmployeeManagementService service) throws EmployeeManagementFault {
        LOGGER.info("\n--- Test: Get All Active Employees ---");
        List<Employee> employees = service.getAllActiveEmployees();
        for (Employee emp : employees) {
            LOGGER.info("  " + emp.getEmployeeId() + ": " + emp.getFirstName() + " " + emp.getLastName() +
                    " (" + emp.getDepartment() + ") - $" + emp.getSalary());
        }
    }

    private static void testGetEmployeesByDepartment(EmployeeManagementService service) throws EmployeeManagementFault {
        LOGGER.info("\n--- Test: Get Employees By Department ---");
        List<Employee> engineers = service.getEmployeesByDepartment("Engineering");
        LOGGER.info("Engineering department employees: " + engineers.size());
        for (Employee emp : engineers) {
            LOGGER.info("  " + emp.getFirstName() + " " + emp.getLastName() + " - " + emp.getPosition());
        }
    }

    private static void testUpdateSalary(EmployeeManagementService service) throws EmployeeManagementFault {
        LOGGER.info("\n--- Test: Update Salary ---");
        SalaryUpdateResult result = service.updateSalary(1001, 105000.0,
                LocalDate.now().toString(), "Annual salary adjustment");
        LOGGER.info("Success: " + result.isSuccess());
        LOGGER.info("Previous: $" + result.getPreviousSalary() + " -> New: $" + result.getNewSalary());
        LOGGER.info("Message: " + result.getMessage());
    }

    private static void testApplyPercentageRaise(EmployeeManagementService service) throws EmployeeManagementFault {
        LOGGER.info("\n--- Test: Apply Percentage Raise ---");
        SalaryUpdateResult result = service.applyPercentageRaise(1002, 8.5,
                LocalDate.now().toString());
        LOGGER.info("Success: " + result.isSuccess());
        LOGGER.info("Message: " + result.getMessage());
    }

    private static void testDepartmentWideRaise(EmployeeManagementService service) throws EmployeeManagementFault {
        LOGGER.info("\n--- Test: Department Wide Raise ---");
        List<SalaryUpdateResult> results = service.applyDepartmentWideRaise("Engineering", 5.0,
                LocalDate.now().toString());
        for (SalaryUpdateResult result : results) {
            LOGGER.info("  Employee " + result.getEmployeeId() + ": $" +
                    result.getPreviousSalary() + " -> $" + result.getNewSalary());
        }
    }

    private static void testSubmitPerformanceReview(EmployeeManagementService service) throws EmployeeManagementFault {
        LOGGER.info("\n--- Test: Submit Performance Review ---");
        PerformanceReview review = new PerformanceReview();
        review.setEmployeeId(1001);
        review.setReviewerName("Jane Manager");
        review.setProductivityScore(4.5);
        review.setTeamworkScore(4.0);
        review.setLeadershipScore(4.2);
        review.setCommunicationScore(4.8);
        review.setReviewPeriod("Annual-2024");
        review.setComments("Excellent performance throughout the year. Strong technical skills and leadership.");

        ReviewResult result = service.submitPerformanceReview(review);
        LOGGER.info("Review submitted. Score: " + result.getOverallScore());
        LOGGER.info("Promotion recommended: " + result.isPromotionRecommended());
        LOGGER.info("Suggested raise: " + result.getSuggestedSalaryIncrease() + "%");
    }

    private static void testGetPerformanceReviews(EmployeeManagementService service) throws EmployeeManagementFault {
        LOGGER.info("\n--- Test: Get Performance Reviews ---");
        List<PerformanceReview> reviews = service.getPerformanceReviews(1001);
        LOGGER.info("Reviews found: " + reviews.size());
        for (PerformanceReview review : reviews) {
            LOGGER.info("  Review " + review.getReviewId() + ": Score=" + review.getOverallScore() +
                    ", Period=" + review.getReviewPeriod());
        }

        double latestScore = service.getLatestPerformanceScore(1001);
        LOGGER.info("Latest performance score: " + latestScore);
    }

    private static void testTerminateEmployee(EmployeeManagementService service) throws EmployeeManagementFault {
        LOGGER.info("\n--- Test: Terminate Employee ---");
        TerminationResult result = service.terminateEmployee(1003,
                LocalDate.now().toString(), "Position eliminated due to restructuring", true);
        LOGGER.info("Termination success: " + result.isSuccess());
        LOGGER.info("Final pay: $" + result.getFinalPayAmount());
        LOGGER.info("Eligible for rehire: " + result.isEligibleForRehire());
        LOGGER.info("Message: " + result.getMessage());
    }

    private static void testRehireEmployee(EmployeeManagementService service) throws EmployeeManagementFault {
        LOGGER.info("\n--- Test: Rehire Employee ---");
        boolean rehired = service.rehireEmployee(1003, "Senior Financial Analyst",
                82000.0, LocalDate.now().toString());
        LOGGER.info("Rehire success: " + rehired);

        Employee emp = service.getEmployee(1003);
        LOGGER.info("Rehired employee: " + emp.getFirstName() + " " + emp.getLastName() +
                " | Position: " + emp.getPosition() + " | Salary: $" + emp.getSalary() +
                " | Status: " + emp.getStatus());
    }

    private static void testErrorHandling(EmployeeManagementService service) {
        LOGGER.info("\n--- Test: Error Handling ---");

        // Test: Non-existent employee
        try {
            service.getEmployee(9999);
        } catch (EmployeeManagementFault e) {
            LOGGER.info("Expected error (non-existent employee): " + e.getMessage());
        }

        // Test: Invalid salary
        try {
            service.updateSalary(1001, -5000, LocalDate.now().toString(), "Invalid");
        } catch (EmployeeManagementFault e) {
            LOGGER.info("Expected error (invalid salary): " + e.getMessage());
        }

        // Test: Invalid date
        try {
            service.updateSalary(1001, 100000, "invalid-date", "Test");
        } catch (EmployeeManagementFault e) {
            LOGGER.info("Expected error (invalid date): " + e.getMessage());
        }

        // Test: Invalid performance score
        try {
            PerformanceReview review = new PerformanceReview();
            review.setEmployeeId(1001);
            review.setProductivityScore(6.0); // Invalid: > 5.0
            review.setTeamworkScore(4.0);
            review.setLeadershipScore(4.0);
            review.setCommunicationScore(4.0);
            service.submitPerformanceReview(review);
        } catch (EmployeeManagementFault e) {
            LOGGER.info("Expected error (invalid score): " + e.getMessage());
        }

        LOGGER.info("\n==========================================");
        LOGGER.info("All tests completed!");
    }
}